$1<script>
(function(){
try{
  var scriptEl = document.currentScript;
  if(!scriptEl) return;
  var D=document;
  (async function(){
    try{
      var settings=null;
      try{ settings = tavo.get('emo_settings'); }catch(e){}
      settings = settings || {enabled:true,rate:70,cats:['happy','sad','angry','shy','love','surprised','sleepy','confused','scared','proud']};
      if(!settings.enabled) return;
      if(Math.random()*100 > (settings.rate==null?70:settings.rate)) return;

      var msg = await tavo.message.current();
      var text = (msg && msg.content) || '';

      var DICT={
        happy:['开心','高兴','笑了','哈哈','嘻嘻','快乐','愉快','欣喜','太棒了','哈哈哈','咧嘴笑','灿烂'],
        sad:['难过','伤心','哭','泪','悲伤','委屈','呜呜','心痛','失落','泣不成声'],
        angry:['生气','愤怒','气死','讨厌','可恶','恼火','火大','怒','咬牙'],
        shy:['脸红','害羞','羞涩','不好意思','尴尬','捂脸','支支吾吾','结结巴巴'],
        love:['喜欢你','爱你','心动','亲亲','抱抱','宝贝','想你','心跳','爱意'],
        surprised:['惊讶','震惊','天哪','不会吧','惊呆','吓了一跳','怎么会'],
        sleepy:['困','好累','打哈欠','想睡','睡着了','疲惫不堪','哈欠'],
        confused:['疑惑','好奇怪','不懂','困惑','迷茫','搞不清楚','一头雾水'],
        scared:['害怕','恐惧','吓人','瑟瑟发抖','恐怖','惊恐','发抖'],
        proud:['得意','骄傲','哼','自豪','炫耀','挑眉'],
      };
      var PROMPTS={
        happy:'cute chibi white bear sticker, sticker pack style, thick bold black outline, flat simple colors, plain white background, laughing joyfully with closed eyes, dynamic happy pose, no text, square composition, high quality vector illustration',
        sad:'cute chibi white bear sticker, sticker pack style, thick bold black outline, flat simple colors, plain white background, crying with big teardrops, sorrowful droopy expression, no text, square composition, high quality vector illustration',
        angry:'cute chibi white bear sticker, sticker pack style, thick bold black outline, flat simple colors, plain white background, puffed cheeks furrowed brows steam from head fists clenched angry, no text, square composition, high quality vector illustration',
        shy:'cute chibi white bear sticker, sticker pack style, thick bold black outline, flat simple colors, plain white background, blushing cheeks covering face with paws looking away bashfully shy, no text, square composition, high quality vector illustration',
        love:'cute chibi white bear sticker, sticker pack style, thick bold black outline, flat simple colors, plain white background, heart shaped eyes holding a red heart blushing happily in love, no text, square composition, high quality vector illustration',
        surprised:'cute chibi white bear sticker, sticker pack style, thick bold black outline, flat simple colors, plain white background, wide open eyes mouth open in shock surprised, no text, square composition, high quality vector illustration',
        sleepy:'cute chibi white bear sticker, sticker pack style, thick bold black outline, flat simple colors, plain white background, drowsy half closed eyes yawning holding a pillow sleepy, no text, square composition, high quality vector illustration',
        confused:'cute chibi white bear sticker, sticker pack style, thick bold black outline, flat simple colors, plain white background, tilted head puzzled confused expression, no text, square composition, high quality vector illustration',
        scared:'cute chibi white bear sticker, sticker pack style, thick bold black outline, flat simple colors, plain white background, trembling wide scared eyes sweat drop hiding behind paws, no text, square composition, high quality vector illustration',
        proud:'cute chibi white bear sticker, sticker pack style, thick bold black outline, flat simple colors, plain white background, smug confident smirk arms crossed sparkle effects proud, no text, square composition, high quality vector illustration',
      };
      var EMOJI_FALLBACK={
        happy:'😄',sad:'😢',angry:'😠',shy:'😳',love:'😍',
        surprised:'😱',sleepy:'😴',confused:'😕',scared:'😨',proud:'😏',
      };

      var best=null,bestScore=0;
      Object.keys(DICT).forEach(function(cat){
        if(settings.cats && settings.cats.indexOf(cat)===-1) return;
        var score=0;
        DICT[cat].forEach(function(kw){ if(text.indexOf(kw)>-1) score++; });
        if(score>bestScore){ bestScore=score; best=cat; }
      });
      if(!best || bestScore===0) return;

      var holder=document.createElement('span');
      holder.style.cssText='display:inline-block;vertical-align:middle;margin-left:4px;opacity:0;transform:scale(0.2);';
      scriptEl.parentNode.insertBefore(holder, scriptEl);

      var stickerPath=null;
      try{
        var fname='sticker_'+best+'.png';
        if(await tavo.file.exists(fname,{scope:'global'})){
          stickerPath=tavo.file.url(fname,'global');
        } else {
          stickerPath=await tavo.image.generate(PROMPTS[best], {aspectRatio:'1:1', saveAs:fname, scope:'global'});
        }
      }catch(e){ console.error('[表情包-生成失败,回退emoji]',e); }

      if(stickerPath){
        holder.innerHTML='<img src="'+stickerPath+'" style="width:60px;height:60px;object-fit:contain;border-radius:10px;cursor:pointer;" onclick="try{tavo.utils.preview(this.src)}catch(e){}" />';
      } else {
        holder.textContent=' '+(EMOJI_FALLBACK[best]||'');
        holder.style.fontSize='28px';
      }

      if(holder.animate){
        holder.animate(
          [{transform:'scale(0.2)',opacity:0},{transform:'scale(1.15)',opacity:1},{transform:'scale(1)',opacity:1}],
          {duration:420,easing:'cubic-bezier(.34,1.56,.64,1)',fill:'forwards'}
        );
      } else { holder.style.transform='scale(1)'; holder.style.opacity='1'; }
    }catch(err){ console.error('[表情包插件-检测]',err); }
  })();
}catch(e){console.error('[表情包插件-检测]',e);}
})();
</script>
